from dataclasses import dataclass
from typing import List

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: List[Triple]) -> str:
    """
    Convert a list of triples about airports (or related entities) into a single
    fluent sentence. Unknown predicates fall back to a generic phrasing.
    """
    if not triples:
        return ""

    def _clean(val: str) -> str:
        """Remove surrounding quotes if present."""
        return val.strip('"').strip("'")

    def _ordinal(n: str) -> str:
        """Convert ordinal prefix to English word."""
        return {"1st": "first", "2nd": "second", "3rd": "third", "4th": "fourth", "5th": "fifth"}.get(n, n.lower())

    # Identify the main subject (the airport entity that appears most as subject)
    subject_counts = {}
    for t in triples:
        subject_counts[t.subject] = subject_counts.get(t.subject, 0) + 1
    subject = max(subject_counts, key=subject_counts.get)

    # Group predicates by category for better sentence structure
    location_facts = []
    runway_facts = []
    operational_facts = []
    identifier_facts = []
    other_facts = []

    for t in triples:
        s = t.subject
        p = t.predicate
        o = _clean(t.object)

        if p == "cityServed":
            location_facts.append(f"serves the city of {o}")
        elif p == "location":
            location_facts.append(f"located in {o}")
        elif p == "country":
            location_facts.append(f"which is in {o}")
        elif p == "isPartOf":
            location_facts.append(f"which is part of {o}")
        elif p == "elevationAboveTheSeaLevel":
            location_facts.append(f"at an elevation of {o} metres above sea level")
        elif p == "elevationAboveTheSeaLevelInFeet":
            location_facts.append(f"at an elevation of {o} feet above sea level")
        elif p == "elevationAboveTheSeaLevelInMetres":
            location_facts.append(f"at an elevation of {o} metres above sea level")
        elif p.endswith("RunwayLengthFeet"):
            idx = _ordinal(p.split("Runway")[0])
            runway_facts.append(f"{idx} runway is {o} feet long")
        elif p.endswith("RunwayLengthMetre"):
            idx = _ordinal(p.split("Runway")[0])
            runway_facts.append(f"{idx} runway is {o} metres long")
        elif p == "runwayLength":
            runway_facts.append(f"a runway length of {o}")
        elif p.endswith("RunwaySurfaceType") or p == "runwaySurfaceType":
            runway_facts.append(f"{o} surface")
        elif p == "runwayName":
            runway_facts.append(f"named {o}")
        elif p == "operatingOrganisation":
            operational_facts.append(f"operated by {o}")
        elif p == "owner":
            operational_facts.append(f"owned by {o}")
        elif p == "icaoLocationIdentifier":
            identifier_facts.append(f"ICAO code {o}")
        elif p == "iataLocationIdentifier":
            identifier_facts.append(f"IATA code {o}")
        elif p == "locationIdentifier":
            identifier_facts.append(f"code {o}")
        else:
            # Handle unknown predicates more gracefully
            other_facts.append(f"{p.replace('_', ' ')} is {o}")

    # Build coherent sentence with proper connectors
    parts = [subject]
    connectors = []

    # Add location facts first
    if location_facts:
        connectors.append(", ".join(location_facts))

    # Add runway facts
    if runway_facts:
        connectors.append("with " + ", ".join(runway_facts))

    # Add operational facts
    if operational_facts:
        connectors.append("and " + ", ".join(operational_facts))

    # Add identifier facts
    if identifier_facts:
        connectors.append("with " + ", ".join(identifier_facts))

    # Add other facts
    if other_facts:
        connectors.append("including " + ", ".join(other_facts))

    # Join all parts with proper punctuation
    if connectors:
        sentence = f"{subject} {connectors[0]}"
        for conn in connectors[1:]:
            sentence += f", {conn}"
    else:
        sentence = subject

    # Clean up the sentence
    sentence = sentence.strip()
    # Fix double spaces
    while "  " in sentence:
        sentence = sentence.replace("  ", " ")
    # Add period at end
    if not sentence.endswith("."):
        sentence += "."

    return sentence[0].upper() + sentence[1:]

# EVOLVE-BLOCK-END
